plan.raw_text:
{
  "goal": "为用户推荐一个详细的北京3天旅游计划",
  "graph_policy": {
    "max_parallelism": 1,
    "fail_fast": true
  },
  "steps": [
    {
      "title": "提取需求约束",
      "instruction": "整理用户已给出的旅游天数、饮食偏好（爱吃天使）与时间约束，输出结构化约束清单。",
      "depends_on": [],
      "input_bindings": []
    },
    {
      "title": "生成候选行程",
      "instruction": "基于约束清单生成 2 套三日行程候选，每套包含每日安排与交通建议。",
      "depends_on": ["S1"],
      "input_bindings": [
        {"from": "S1.output_text", "to": "constraints"}
      ]
    },
    {
      "title": "形成最终方案",
      "instruction": "对候选行程进行优化与取舍，输出推荐方案、每日详细行程和注意事项。",
      "depends_on": ["S2"],
      "input_bindings": [
        {"from": "S2.output_text", "to": "itinerary_candidates"}
      ]
    }
  ]
}
